/* ===== 清透水滴主题 v3.3 ===== */

/* ===== 变量 ===== */

:root{

--bubble-ai: rgba(220,255,235,0.22);
--bubble-user: rgba(190,255,210,0.22);

--Char头像框:url("https://s41.ax1x.com/2026/03/14/peE3C0P.png");
--User头像框:url("https://s41.ax1x.com/2026/03/14/peE3e6s.png");

}

/* ===== 背景透明 ===== */

#chat{
background:transparent !important;
}

/* ===== 消息结构 ===== */

.mes{

display:flex!important;
flex-direction:column!important;

align-items:center!important;

background:transparent!important;
border:none!important;

gap:6px;
padding-top:25px!important;

}

.mes_block{
display:contents;
}

/* ===== 头像 ===== */

.mes .avatar{

position:relative!important;

display:flex!important;
justify-content:center;
align-items:center;

order:1;

}

.mes .avatar img{

border-radius:50%!important;
border:none!important;

}

/* 头像框 */

.mes .avatar::after{

content:"";

position:absolute;

top:42%;
left:50%;

transform:translate(-50%,-50%);

width:125%;
height:125%;

background-size:contain;
background-repeat:no-repeat;
background-position:center;

pointer-events:none;

}

.mes[is_user="false"] .avatar::after{
background-image:var(--Char头像框);
}

.mes[is_user="true"] .avatar::after{
background-image:var(--User头像框);
}

/* ===== 名字 ===== */

.mes .ch_name{

order:2;

font-weight:bold;

color:#000;

font-family:
"STXingkai",
"华文行楷",
"KaiTi",
serif;

text-align:center;

margin-top:4px;

}

/* ===== 时间 ===== */

.mes_timer,
.mesIDDisplay{

order:3;
font-size:12px;
text-align:center;

}

/* ===== 水滴气泡 ===== */

.mes_text{

order:4;

font-family:
"STFangsong",
"华文仿宋",
"FangSong",
serif;

/* 清透水滴 */

background:var(--bubble-ai);

/* 轻微玻璃 */

backdrop-filter:blur(6px);
-webkit-backdrop-filter:blur(6px);

/* 删除边框 */

border:none;

/* 水滴形状 */

border-radius:26px;

padding:14px 22px;

width:85%;
max-width:85%;

box-sizing:border-box;

text-align:center;

/* 水滴高光 */

box-shadow:

inset 3px 3px 6px rgba(255,255,255,0.75),
inset -4px -4px 10px rgba(0,0,0,0.06),
0 4px 12px rgba(0,0,0,0.05);

}

/* 用户气泡 */

.mes[is_user="true"] .mes_text{

background:var(--bubble-user);

}

/* ===== 输入框 ===== */

#send_form{

background:rgba(255,255,255,0.25)!important;

backdrop-filter:blur(10px);

border-radius:30px!important;

border:1px solid rgba(120,220,150,0.6);

}

/* ===== 顶部栏 ===== */

#top-settings-holder{

background:rgba(255,255,255,0.2);

backdrop-filter:blur(10px);

border-radius:20px;

}

/* ===== 滚动条 ===== */

::-webkit-scrollbar{
width:4px;
}

::-webkit-scrollbar-thumb{

background:linear-gradient(to bottom,#98FB98,#3CB371);

border-radius:10px;

}

/* ===== 编辑按钮 ===== */

.mes_buttons,
.mes_edit_buttons{

position:absolute !important;

top:12px;
right:6px;

opacity:0.7;

transition:0.2s;

}

.mes:hover .mes_buttons,
.mes:hover .mes_edit_buttons{

opacity:1;

}

/* ===== 非聊天界面：绿色磨砂玻璃 ===== */

/* 左右抽屉（角色 / 设置 / 世界书等） */

.drawer-content{

background:rgba(230,255,235,0.92) !important;

backdrop-filter:blur(14px);
-webkit-backdrop-filter:blur(14px);

border-left:1px solid rgba(120,220,150,0.35);
border-right:1px solid rgba(120,220,150,0.35);

}

/* 设置窗口 / 弹窗 */

.popup,
.modal,
.menu,
.panel{

background:rgba(230,255,235,0.95) !important;

backdrop-filter:blur(16px);
-webkit-backdrop-filter:blur(16px);

border-radius:18px;

border:1px solid rgba(120,220,150,0.35);

box-shadow:

0 10px 30px rgba(0,0,0,0.15);

}

/* 侧边栏 */

.drawer{

background:rgba(230,255,235,0.92) !important;

backdrop-filter:blur(14px);

}

/* 顶部菜单（聊天以外页面） */

.menu_button,
.top_menu{

background:rgba(230,255,235,0.9);

border-radius:12px;

}

/* 按钮 */

button{

background:rgba(200,255,210,0.9);

border:none;

border-radius:10px;

box-shadow:

0 2px 6px rgba(0,0,0,0.08);

}

/* 按钮悬停 */

button:hover{

background:rgba(180,240,200,1);

}

/* 输入框 */

input,
textarea,
select{

background:rgba(255,255,255,0.95);

border:1px solid rgba(120,220,150,0.45);

border-radius:10px;

}

/* 列表 */

.list-group-item{

background:transparent;

border-bottom:1px solid rgba(120,220,150,0.2);

}

/* 列表悬停 */

.list-group-item:hover{

background:rgba(180,255,200,0.35);

}

/* 卡片 */

.card{

background:rgba(240,255,245,0.95);

border-radius:14px;

border:1px solid rgba(120,220,150,0.3);

}

/* 标题 */

h1,h2,h3{

color:#2f7f55;

}

/* 标签 */

label{

color:#2e6f4e;

}
